    map['amount_paid'] = Variable<int>(amountPaid);
    map['amount_remaining'] = Variable<int>(amountRemaining);
    map['status'] = Variable<String>(status);
    map['created_at'] = Variable<int>(createdAt);
    if (!nullToAbsent || dueAt != null) {
